VALUES
  ('social-worker-moex-07800', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在社區化的過程中，其「公共性」為主要意涵，下列何種說法與其背道而馳？', '["著重地方個別需求，具因地制宜的特色", "以在地人士參與為主，減少中央或地方政府的干預", "大量減少社區內所有的正式機構服務體系，以培養非正式照顧體系", "以社區為服務輸送單位，儘量避免過大的範圍"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07801', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '福利社區化的過程中，相較於行政院文化建設委員會所倡導之社區營造，兩者所結合的社會資源對象， 有何差異，以致績效大不同？', '["企業界與傳播媒體", "社區居民與團體", "專業工作者", "行政體系"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07802', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '非自願性案主常出現的行為特徵，下列那一個答案是錯誤的？', '["認為改變也沒有用", "延遲需求的滿足", "表面順從陽奉陰違", "自我感覺良好"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07803', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '針對藥物濫用者的預估（assessment），社會工作人員一定要熟悉藥物的種類和濫用藥物後的症狀與後果， 也需要針對藥物濫用者的行為有所瞭解。該如何預估當事人藥物濫用的可能性？以下那一項答案是錯誤的？', '["不只從當事人，也要從熟悉當事人生活型態和習慣的他人獲取資訊", "從系統觀點來預估藥物濫用", "預估酗酒者會談技巧之準則，亦可適用在預估藥物濫用者的身上", "運用預估酗酒的工具與程序來預估藥物濫用"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07804', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者不是社區工作人員在動員及組織居民的過程中必備的技術？', '["具備人際互動，與人接觸的技術", "規劃、經營各種方案，促進個人與團體層次的充權", "聚集少數民眾，主導並計劃整體的社區發展計畫", "組織居民，形成合法組織"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07805', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '腦力激盪是任務性團體常運用的一種特殊的方法。下列那一項答案是正確的？', '["在腦力激盪時，團體成員透過分析或批判思考，一起致力於目標的達成", "腦力激盪適用在較大的團體中，且成員的異質性越高，在團體中可獲得較多樣性的意見", "在短時間內（約15分鐘）便可完成討論的程序，會議時間的長短與意見品質無關", "如果團體的問題已經確定，並有清楚的範圍，則腦力激盪會更有效"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07806', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社區照顧的概念，下列何者是錯誤的？', '["「由社區照顧」（care by the community）係指由社區內的機構提供服務，例如：日間照顧、餐飲服務、 社區安養等服務；「在社區內照顧」（care in the community）係指由社區中的鄰居、親戚、朋友、志 工等提供所需服務", "1980年代以前社區照顧與社會工作幾無關係，尤其是社區照顧與社區工作之間更不存在關聯", "社區照顧不只追求服務的品質也要考量成本的高低，成本效益的考量是方案選擇的依據", "社區照顧是福利服務的一環，在概念上與社區工作明顯不同"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07807', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '年第一次專門職業及技術人員高等考試社會工作師考試試題 類       科：社會工作師 甲、申論題部分：（50分） 不必抄題，作答時請將試題題號及答案依照順序寫在申論試卷上，於本試題上作答者，不予計分。 請以藍、黑色鋼筆或原子筆在申論試卷上作答。', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "01a38a7597b2", "answer_pdf_sha1": "7b44c41cbb23", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 99, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07808', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '鄉鎮市長選舉結束，某候選人檢視自己在選區內各里的得票率，發現年輕人比例高的里得票率比較高， 得到一個結論：年輕人是自己的主要支持者。此結論犯了那一種錯誤？', '["區位謬誤（ecological fallacy）", "化約論（reductionism）", "過度概化（overgeneralization）", "系統性誤差（systematic error）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "01a38a7597b2", "answer_pdf_sha1": "7b44c41cbb23", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07809', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '質性研究的資料分析非常複雜，因為大家所採取的分析方法各有不同。但是最終的研究結果仍需自己完 成，下列何者不是質性資料處理的方法？', '["操作化（operationalization）", "編碼（coding）", "撰寫備忘錄（memo）", "概念圖記（concept mapping）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "01a38a7597b2", "answer_pdf_sha1": "7b44c41cbb23", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
